import{_ as i,c as n,a1 as c,o as h}from"./chunks/framework.BDxlaA_J.js";const p=JSON.parse('{"title":"Giả mạo địa chỉ MAC","description":"","frontmatter":{},"headers":[],"relativePath":"vi/categories/ethical-hacking-labs/7-sniffing/2-Spoofing-MAC-address.md","filePath":"vi/categories/ethical-hacking-labs/7-sniffing/2-Spoofing-MAC-address.md"}'),t={name:"vi/categories/ethical-hacking-labs/7-sniffing/2-Spoofing-MAC-address.md"};function o(e,a,l,s,r,g){return h(),n("div",null,a[0]||(a[0]=[c('<h1 id="gia-mao-đia-chi-mac" tabindex="-1">Giả mạo địa chỉ MAC <a class="header-anchor" href="#gia-mao-đia-chi-mac" aria-label="Permalink to &quot;Giả mạo địa chỉ MAC&quot;">​</a></h1><p>MAC spoofing là kỹ thuật thay đổi địa chỉ Media Access Control (MAC) được gán tại nhà máy của giao diện mạng trên thiết bị mạng. Địa chỉ MAC được mã hóa cứng trên bộ điều khiển giao diện mạng (NIC) không thể thay đổi. Tuy nhiên, nhiều trình điều khiển cho phép thay đổi địa chỉ MAC. Ngoài ra, có các công cụ có thể làm cho hệ điều hành tin rằng NIC có địa chỉ MAC do người dùng chọn. Quá trình che giấu địa chỉ MAC được gọi là MAC spoofing. Về cơ bản, MAC spoofing liên quan đến việc thay đổi danh tính của máy tính, vì bất kỳ lý do gì, và nó tương đối dễ dàng.</p><p align="center"><img src="https://d5ngkkf53wl41.cloudfront.net/tutorials/ethical-hacking/mac-address-spoofing.png"></p><h3 id="tai-sao-phai-thay-đoi-đia-chi-mac" tabindex="-1">Tại sao phải thay đổi địa chỉ MAC? <a class="header-anchor" href="#tai-sao-phai-thay-đoi-đia-chi-mac" aria-label="Permalink to &quot;Tại sao phải thay đổi địa chỉ MAC?&quot;">​</a></h3><ul><li>Tăng tính ẩn danh.</li><li>Giả mạo thiết bị khác.</li><li>Bỏ qua bộ lọc.</li></ul><p><strong>lưu ý</strong>: lab sẽ chỉ cho bạn cách thay đổi địa chỉ MAC chỉ trên bộ nhớ không phải vật lý.</p><h3 id="muc-tieu" tabindex="-1">Mục tiêu <a class="header-anchor" href="#muc-tieu" aria-label="Permalink to &quot;Mục tiêu&quot;">​</a></h3><ul><li>Thay đổi địa chỉ MAC trên <strong>Kali Linux</strong>.</li><li>Thay đổi địa chỉ MAC trên <strong>Windows</strong>.</li></ul><h3 id="yeu-cau" tabindex="-1">Yêu cầu <a class="header-anchor" href="#yeu-cau" aria-label="Permalink to &quot;Yêu cầu&quot;">​</a></h3><ul><li>Máy ảo Kali Linux.</li><li>Bộ điều hợp mạng Alfa, hoặc bộ điều hợp khác với chipset tương tự. <a href="https://kennyvn.com/best-wireless-adapters-kali-linux/" target="_blank" rel="noreferrer">[+]</a></li><li>Máy ảo Windows 7, 8 hoặc 10.</li></ul><h2 id="su-dung-macchanger-kali" tabindex="-1">Sử dụng <code>macchanger</code> (Kali) <a class="header-anchor" href="#su-dung-macchanger-kali" aria-label="Permalink to &quot;Sử dụng `macchanger` (Kali)&quot;">​</a></h2><p>Macchanger là công cụ đi kèm với bất kỳ phiên bản Kali Linux rolling edition nào và có thể thay đổi địa chỉ MAC thành bất kỳ địa chỉ mong muốn nào cho đến khi khởi động lại. Trong lab này chúng ta sẽ giả mạo địa chỉ MAC của bộ điều hợp không dây với địa chỉ MAC ngẫu nhiên được tạo bởi <strong>Macchanger trên Kali Linux.</strong></p><p>Kho lưu trữ: <a href="https://github.com/alobbs/macchanger" target="_blank" rel="noreferrer">https://github.com/alobbs/macchanger</a></p><ol start="0"><li><p>Sử dụng <code>ifconfig</code> để xem địa chỉ MAC hiện tại của bộ điều hợp mạng: <code>ifconfig</code></p></li><li><p>Tắt bộ điều hợp mạng: <code>ifconfig wlan1 down</code></p></li><li><p>Tiếp theo, thay đổi địa chỉ MAC thành địa chỉ MAC ngẫu nhiên mới bằng <code>macchanger</code>: <code>macchanger -r wlan1</code></p></li></ol><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Current MAC:   f2:30:a0:1a:41:b3 (unknown)</span></span>\n<span class="line"><span>Permanent MAC: 00:c1:c8:a1:e7:d1 (ALFA, INC.)</span></span>\n<span class="line"><span>New MAC:       ce:11:9a:98:fe:ad (unknown)</span></span></code></pre></div><h2 id="thay-đoi-đia-chi-mac-thu-cong-kali" tabindex="-1">Thay đổi địa chỉ MAC thủ công (Kali) <a class="header-anchor" href="#thay-đoi-đia-chi-mac-thu-cong-kali" aria-label="Permalink to &quot;Thay đổi địa chỉ MAC thủ công (Kali)&quot;">​</a></h2><ol start="0"><li><p>Tắt bộ điều hợp mạng: <code>ifconfig wlan0 down</code></p></li><li><p>Thay đổi địa chỉ bằng tùy chọn <code>hw ether</code> từ <strong>ifconfig</strong> sử dụng bất kỳ địa chỉ MAC nào bạn muốn: <code>ifconfig wlan0 hw ether 00:11:22:33:44:55</code></p></li><li><p>Bật giao diện: <code>ifconfig wlan0 up</code></p></li><li><p>Kiểm tra thay đổi của bộ điều hợp mạng: <code>ifconfig</code></p></li></ol><hr><h2 id="smac-gui-tool-windows" tabindex="-1">SMAC GUI Tool (Windows) <a class="header-anchor" href="#smac-gui-tool-windows" aria-label="Permalink to &quot;SMAC GUI Tool (Windows)&quot;">​</a></h2><p>SMAC là công cụ mạnh mẽ và dễ sử dụng để thay đổi địa chỉ MAC (spoofer). Công cụ có thể kích hoạt địa chỉ MAC mới ngay sau khi thay đổi tự động.</p><p><a href="https://smac.soft32.com/" target="_blank" rel="noreferrer">https://smac.soft32.com/</a></p><p><img src="https://thegeekpage.com/wp-content/uploads/2016/05/mac-address-changer-tool.gif" alt="smac"></p>',22)]))}const u=i(t,[["render",o]]);export{p as __pageData,u as default};
